//! v0.2.1 trybuild UI tests for `uor_ground!`, `#[derive(ConstrainedType)]`,
//! and `#[uor_grounded]`.
//!
//! Each `tests/ui/*.rs` file is a compile-fail fixture that exercises a
//! documented error path. The matching `.stderr` file is generated by
//! `TRYBUILD=overwrite cargo test` and checked into the repo.

#[test]
fn ui() {
    let t = trybuild::TestCases::new();
    t.compile_fail("tests/ui/uor_ground_missing_as_clause.rs");
    t.compile_fail("tests/ui/uor_ground_unknown_keyword.rs");
    t.compile_fail("tests/ui/uor_grounded_invalid_level.rs");
}
